patch:
diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index 025234c54956..adf4c5bf0d67 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -1008,6 +1008,7 @@ bool VectorCombine::scalarizeBinopOrCmp(Instruction &I) {
   if (IsConst1)
     V1 = ConstantExpr::getExtractElement(VecC1, Builder.getInt64(Index));

+
   Value *Scalar =
       IsCmp ? Builder.CreateCmp(Pred, V0, V1)
             : Builder.CreateBinOp((Instruction::BinaryOps)Opcode, V0, V1);
@@ -1067,6 +1068,8 @@ bool VectorCombine::foldExtractedCmps(Instruction &I) {
   unsigned CmpOpcode = CmpInst::isFPPredicate(Pred) ? Instruction::FCmp
                                                     : Instruction::ICmp;
   auto *VecTy = dyn_cast<FixedVectorType>(X->getType());
+  if (I.isBinaryOp() && !cast<BinaryOperator>(&I)->isCommutative() && ConvertToShuf == Ext0)
+    return false;
   if (!VecTy)
     return false;

